  private sortIcon(col: DataTableColumn): string {
    if (this.sortKey !== col.key) return "↕";
    return this.sortDir === "asc" ? "↑" : "↓";
  }

  private ariaSortAttr(col: DataTableColumn): string {
    if (this.sortKey !== col.key) return "none";
