                  aria-sort=${sortable ? this.ariaSortAttr(col) : ""}
                  tabindex=${sortable ? "0" : ""}
                  @click=${sortable ? () => this.toggleSort(col) : null}
                  @keydown=${sortable ? (e: KeyboardEvent) => this.onHeaderKeyDown(e, col) : null}
                >
