      padding: var(--lv-space-2) var(--lv-space-3);
      border-radius: var(--lv-radius-sm, var(--lv-radius-md));
      color: var(--lv-color-fg); text-decoration: none;
    }
    .lv-nav__item-link:hover, .lv-nav__item-link:focus-visible {
